Simpar3 <- function(n1) {
  L2distance <- matrix(NA, ncol=n1, nrow=n1)
  data <- rnorm(n1)
  diag(L2distance)=0
  cl <- makeCluster(4)
  registerDoParallel(cl)
  foreach(j=1:n1)  %dopar% {
    library(np)
    datj <- data[j]
    for(k in j:n1) {
      L2distance[j,k] <- k*datj
    }
  }
  stopCluster(cl)
  return(L2distance)
}

